# Module: vehicle_base
# Defines base vehicle class with virtual methods for cross-module inheritance testing

class Vehicle:
    brand: str

    def __init__(self, brand: str):
        self.brand = brand

    @virtual
    def description(self) -> str:
        return f"Generic {self.brand}"

    @virtual
    def wheel_count(self) -> int:
        return 0

